                value: "<!DOCTYPE html>\r\n<html lang=\"en\" style=\"margin:0;padding:0;\">\r\n  <head>\r\n    <meta charset=\"utf-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\" />\r\n    <meta name=\"x-apple-disable-message-reformatting\" />\r\n    <meta name=\"format-detection\" content=\"telephone=no,address=no,email=no,date=no,url=no\" />\r\n    <meta name=\"color-scheme\" content=\"light dark\" />\r\n    <meta name=\"supported-color-schemes\" content=\"light dark\" />\r\n    <title>Reset Your Password</title>\r\n    <style>\r\n      body {\r\n        margin:0;\r\n        padding:0;\r\n        background:linear-gradient(135deg,#e6f0ff,#f9fbff);\r\n        font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,Ubuntu,'Helvetica Neue',Arial,sans-serif;\r\n        color:#1e2330;\r\n      }\r\n      .container {\r\n        max-width:800px;\r\n        margin:0 auto;\r\n        padding:32px 20px;\r\n      }\r\n      .card {\r\n        background:rgba(255,255,255,0.85);\r\n        border-radius:16px;\r\n        padding:32px;\r\n        box-shadow:0 8px 20px rgba(0,0,0,0.1);\r\n      }\r\n      h1 {\r\n        margin:0 0 20px 0;\r\n        font-size:24px;\r\n        font-weight:600;\r\n        color:#0b5fff;\r\n        text-align:center;\r\n      }\r\n      p {\r\n        margin:0 0 16px 0;\r\n        font-size:16px;\r\n        line-height:1.6;\r\n      }\r\n      .cta {\r\n        display:block;\r\n        margin:20px auto 10px auto;\r\n        width:max-content;\r\n        text-decoration:none;\r\n        background:#0b5fff;\r\n        color:#ffffff !important;\r\n        padding:12px 20px;\r\n        border-radius:10px;\r\n        font-weight:600;\r\n      }\r\n      .link-fallback {\r\n        background:#f1f4fb;\r\n        border-radius:8px;\r\n        padding:12px 16px;\r\n        margin:12px 0 0 0;\r\n        font-family:monospace;\r\n        font-size:14px;\r\n        color:#0b5fff;\r\n        word-break:break-all;\r\n      }\r\n      .footer {\r\n        margin-top:28px;\r\n        font-size:12px;\r\n        color:#6b7280;\r\n        text-align:center;\r\n      }\r\n      @media (max-width:600px) {\r\n        .card { padding:20px; }\r\n        h1 { font-size:20px; }\r\n        p { font-size:15px; }\r\n      }\r\n      @media (prefers-color-scheme: dark) {\r\n        body {\r\n          background:linear-gradient(135deg,#0f1115,#1b1e24);\r\n          color:#e7e7ea;\r\n        }\r\n        .card {\r\n          background:rgba(30,33,40,0.85);\r\n          border:1px solid #2a2f3a;\r\n        }\r\n        h1 { color:#7cb8ff; }\r\n        .link-fallback {\r\n          background:#252b36;\r\n          color:#7cb8ff;\r\n        }\r\n        .footer { color:#a7acb8; }\r\n      }\r\n    </style>\r\n  </head>\r\n  <body>\r\n    <div class=\"container\">\r\n      <div class=\"card\">\r\n        <h1>Reset Your Password</h1>\r\n        <p>Hello <strong>{{User}}</strong>,</p>\r\n        <p>We received a request to reset your password. Click the button below to create a new one:</p>\r\n\r\n        <!-- Primary CTA uses the reset link -->\r\n        <a class=\"cta\" href=\"{{ResetLink}}\" target=\"_blank\" rel=\"noopener\">Reset Password</a>\r\n\r\n        <!-- Fallback plain link (placed under {{ResetLink}}) -->\r\n        <div class=\"link-fallback\">\r\n          {{ResetLink}}\r\n        </div>\r\n\r\n        <p style=\"margin-top:16px;\">If you didn’t request a password reset, you can safely ignore this email.</p>\r\n        <p>Best regards,<br/>PublicQ Team</p>\r\n\r\n        <div class=\"footer\">\r\n          This link will expire after a short period for security reasons.\r\n        </div>\r\n      </div>\r\n    </div>\r\n  </body>\r\n</html>");

